concept.syntax:
var name: String  = "Alice"  // cannot be null
var nick: String? = null      // nullable

// Safe call — returns null if nick is null
val len = nick?.length        // Int? — could be null

// Elvis — fallback when null
val display = nick ?: "anonymous"  // String

// let — block only runs when non-null
nick?.let { println(it.uppercase()) }

// !! — assert non-null (crashes if null)
val forced = nick!!.length    // NPE if nick is null

demo.code:
fun greet(name: String?): String {
    val safe = name ?: "stranger"
    return "Hello, $safe!"
}

fun main() {
    println(greet("Alice"))
    println(greet(null))
}

